return function(scaleType)
    if scaleType > 2.5 then
        if not assets_3x then make_assets_3x() end
        return assets_3x, 3
    elseif scaleType > 1.5 then
        if not assets_2x then make_assets_2x() end
        return assets_2x, 2
    end
    if not assets_1x then make_assets_1x() end
    return assets_1x, 1
end
